import { useState } from 'react';
import api from '../api/axios';

function Upload() {
  const [form, setForm] = useState({
    title: '',
    description: '',
    category: '',
    videoUrl: '',
    thumbnailUrl: '',
    duration: ''
  });
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');

  const submitHandler = async (event) => {
    event.preventDefault();
    setMessage('');
    setError('');

    try {
      await api.post('/videos/upload', {
        ...form,
        duration: Number(form.duration || 0)
      });
      setMessage('Video uploaded successfully');
      setForm({ title: '', description: '', category: '', videoUrl: '', thumbnailUrl: '', duration: '' });
    } catch (requestError) {
      setError(requestError.response?.data?.message || 'Upload failed');
    }
  };

  return (
    <div className="row">
      <div className="col-lg-8">
        <div className="card shadow-sm">
          <div className="card-body">
            <h4 className="mb-3">Upload Video</h4>
            <form onSubmit={submitHandler}>
              <div className="mb-3">
                <label className="form-label">Title</label>
                <input
                  className="form-control"
                  required
                  value={form.title}
                  onChange={(event) => setForm({ ...form, title: event.target.value })}
                />
              </div>
              <div className="mb-3">
                <label className="form-label">Description</label>
                <textarea
                  className="form-control"
                  rows="3"
                  value={form.description}
                  onChange={(event) => setForm({ ...form, description: event.target.value })}
                />
              </div>
              <div className="row">
                <div className="col-md-6 mb-3">
                  <label className="form-label">Category</label>
                  <input
                    className="form-control"
                    value={form.category}
                    onChange={(event) => setForm({ ...form, category: event.target.value })}
                  />
                </div>
                <div className="col-md-6 mb-3">
                  <label className="form-label">Duration (seconds)</label>
                  <input
                    className="form-control"
                    type="number"
                    min="0"
                    value={form.duration}
                    onChange={(event) => setForm({ ...form, duration: event.target.value })}
                  />
                </div>
              </div>
              <div className="mb-3">
                <label className="form-label">Video URL</label>
                <input
                  className="form-control"
                  required
                  value={form.videoUrl}
                  onChange={(event) => setForm({ ...form, videoUrl: event.target.value })}
                />
              </div>
              <div className="mb-3">
                <label className="form-label">Thumbnail URL</label>
                <input
                  className="form-control"
                  value={form.thumbnailUrl}
                  onChange={(event) => setForm({ ...form, thumbnailUrl: event.target.value })}
                />
              </div>

              {message && <div className="alert alert-success py-2">{message}</div>}
              {error && <div className="alert alert-danger py-2">{error}</div>}

              <button className="btn btn-primary" type="submit">
                Submit Upload
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Upload;
